import React, { useState, useEffect, useRef } from 'react';
import '../assets/styles/Keyboard_mouse.css'; // Importă stilurile tale

const Keyboard_mouse = () => {
  const [startTouch, setStartTouch] = useState(null);  // Punctul de început al atingerii
  const [isClick, setIsClick] = useState(true);  // Detectăm dacă este un click sau o mișcare
  const [cursorPosition, setCursorPosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const socketRef = useRef(null);  // Referință la WebSocket

  const sensitivity = 2;

  // Conectăm WebSocket la server când componenta este montată
  useEffect(() => {
    socketRef.current = new WebSocket('ws://localhost:8000/ws/touchpad/');
    socketRef.current.onopen = () => {
      console.log('WebSocket Connected');
    };
    socketRef.current.onclose = () => {
      console.log('WebSocket Disconnected');
    };
    return () => socketRef.current.close();
  }, []);

  const handleTouchStart = (event) => {
    const touch = event.touches[0];
    setStartTouch({ x: touch.clientX, y: touch.clientY });
    setIsClick(true);
  };

  const handleTouchMove = (event) => {
    event.preventDefault();
    const touch = event.touches[0];

    if (startTouch) {
      const deltaX = (touch.clientX - startTouch.x) * sensitivity;
      const deltaY = (touch.clientY - startTouch.y) * sensitivity;

      if (Math.abs(deltaX) > 5 || Math.abs(deltaY) > 5) {
        setIsClick(false);
      }

      // Trimitem mișcarea la server prin WebSocket
      socketRef.current.send(JSON.stringify({
        action: 'move',
        x: deltaX,
        y: deltaY,
      }));

      // Actualizăm poziția cursorului local
      setCursorPosition((prevPos) => ({
        x: prevPos.x + deltaX,
        y: prevPos.y + deltaY,
      }));

      setStartTouch({ x: touch.clientX, y: touch.clientY });
    }
  };

  const handleTouchEnd = () => {
    if (isClick) {
      // Trimitem clickul stânga prin WebSocket
      socketRef.current.send(JSON.stringify({ action: 'click', button: 'left' }));
    }
    setStartTouch(null);
  };

  return (
    <div
      className="touchpad-container"
      onTouchStart={handleTouchStart}
      onTouchMove={handleTouchMove}
      onTouchEnd={handleTouchEnd}
    >
      <div
        className="cursor"
        style={{
          position: 'absolute',
          left: `${cursorPosition.x}px`,
          top: `${cursorPosition.y}px`,
          width: '10px',
          height: '10px',
          backgroundColor: 'black',
          borderRadius: '50%',
        }}
      ></div>
      <h2>Touchpad Controller</h2>
      <p>Use the touchpad to move the mouse and tap to click.</p>
    </div>
  );
};

export default Keyboard_mouse;
